<template>
  <svg class="svg-defs" aria-hidden="true" width="0" height="0"><defs><marker id="flow-arrow" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="#94a3b8" /></marker></defs></svg>
