        <section v-if="view==='table'||view==='overview'" class="table-wrap"><table><thead><tr><th>Time</th><th>Direction</th><th>From</th><th>To / Queue</th><th>Agent</th><th>Duration</th><th>Status</th><th>Conversation workflow</th></tr></thead><tbody><tr v-for="call in calls.items||[]" :key="call.call_id" :class="{selected:selected?.call.call_id===call.call_id}" @click="selectCall(call.call_id)"><td>{{ time(call.started_at) }}</td><td><span class="direction" :class="call.provider">↘</span> Inbound</td><td>{{ call.phone_number_masked||'Unknown' }}</td><td>—</td><td>{{ call.agent_id||'—' }}</td><td>{{ duration(call.total_latency_ms) }}</td><td><span :class="['status',call.status]">{{ call.status==='failed'?'Missed':call.status==='completed'?'Answered':'Open' }}</span></td><td class="workflow-cell"><div class="workflow-mini"><span>Discover</span><b>→</b><span>Choose</span><b>→</b><span>Demo</span><b>→</b><span :class="{current:call.status==='in_progress'}">{{ call.status==='failed'?'Close':'Answer' }}</span></div></td></tr></tbody></table><p v-if="!(calls.items||[]).length" class="empty">No calls found for these filters.</p></section>
