        <CallDetail v-if="(view==='table'||view==='overview')&&selected" :selected="selected" :detail-tab="detailTab" @update:detail-tab="detailTab=$event" @copy="copy" @export="exportEvents" />
      </section>
      <section v-else-if="tab==='health'" class="health-grid"><article><small>In-progress calls</small><strong>{{ health.inProgressCalls??'—' }}</strong></article><article><small>Postgres pool</small><strong>{{ health.postgres?.total??'—' }}</strong><span>{{ health.postgres?.idle??0 }} idle · {{ health.postgres?.waiting??0 }} waiting</span></article><article><small>Redis</small><strong>{{ health.redis?.available?'Online':'Unavailable' }}</strong></article><article><small>Queue waiting</small><strong>{{ health.queues?.waiting??'—' }}</strong></article></section>
      <section v-else-if="tab==='growth'" class="analytics-page"><div class="analytics-kpis"><article><span class="kpi-icon blue">↗</span><small>Waitlist signups</small><strong>{{ growth.waitlistTotal??'—' }}</strong><em>All time in range</em></article><article><span class="kpi-icon violet">◉</span><small>Demo sessions</small><strong>{{ growth.demoSessions??'—' }}</strong><em>{{ growth.demoCompleted??0 }} completed</em></article><article><span class="kpi-icon amber">▣</span><small>Demo requests</small><strong>{{ growth.demoRequests??'—' }}</strong><em>Inbound interest</em></article><article><span class="kpi-icon green">$</span><small>Sales requests</small><strong>{{ growth.salesRequests??'—' }}</strong><em>Qualified leads</em></article></div><div class="analytics-grid"><article class="analytics-card trend-card"><header><div><h2>Acquisition trend</h2><p>Waitlist signups and demo sessions</p></div><span class="legend"><i class="line-blue"></i>Signups <i class="line-green"></i>Demos</span></header><div class="trend-chart"><div class="axis"><span>40</span><span>30</span><span>20</span><span>10</span><span>0</span></div><div class="trend-bars"><div v-for="(item,index) in (growth.trends?.demos||[])" :key="item.day||index" class="trend-column"><i :style="{height:`${Math.max(8,Math.min(100,(item.count||0)*8))}%`}"></i><b :style="{height:`${Math.max(5,Math.min(100,((growth.trends?.waitlist?.[index]?.count||0)*8)))}%`}"></b><small>{{ item.day?.slice(5)||'—' }}</small></div></div></div></article><article class="analytics-card funnel-card"><header><div><h2>Conversion funnel</h2><p>From interest to action</p></div></header><div class="funnel-list"><div v-for="(item,index) in growth.funnel||[]" :key="item.label"><span>{{ index+1 }}</span><div><b>{{ item.label }}</b><i><em :style="{width:`${Math.max(8,100-index*28)}%`}"></em></i></div><strong>{{ item.count }}</strong></div></div></article><article class="analytics-card"><header><div><h2>Demo languages</h2><p>Sessions by language</p></div></header><div class="rank-list bars-list"><div v-for="item in growth.languages||[]" :key="item.language"><span>{{ item.language||'Unknown' }}</span><i><em :style="{width:`${Math.min(100,(item.count/(growth.demoSessions||1))*100)}%`}"></em></i><strong>{{ item.count }}</strong></div></div></article><article class="analytics-card"><header><div><h2>Use cases</h2><p>What visitors ask for</p></div></header><div class="rank-list"><div v-for="item in growth.demoModes||[]" :key="item.mode"><span>{{ item.mode }}</span><strong>{{ item.count }}</strong></div><div v-if="!(growth.demoModes||[]).length" class="empty">No use-case data yet.</div></div></article></div></section>
